SELECT 
	   , A.RNUM FROM (
	SELECT 
		   , ROWNUM RNUM FROM (
		SELECT


		FROM MST.TB_USER_AUTH_TXN A




		ORDER BY B.SUSER_NM , A.SUSER_GRADE_CD , D.SSVC_LINE_TYPE_CD , F.SLVL_NM , G.SLVL_NM
	) A WHERE ROWNUM <= #{lastIndex}
) A WHERE RNUM >= #{firstIndex}

SELECT DISTINCT B.SSVC_LINE_TYPE_CD , C.SSVC_LINE_TYPE_NM , B.SSVC_GROUP_CD , D.SLVL_NM AS SSVC_GROUP_NM FROM MST.TB_USER_AUTH_TXN A ,MST.TB_LVL_BAS B ,MST.TB_SVC_LINE_TYPE_CD C ,MST.TB_LVL_CD D ,MST.TB_LVL_CD E WHERE 1=1 AND A.SUSER_ID = #{suserId, jdbcType=CHAR}
AND B.SSVC_LINE_TYPE_CD = #{tbLvlBasVo.ssvcLineTypeCd, jdbcType=CHAR}
AND A.NLVL_BAS_SEQ = B.NLVL_BAS_SEQ AND B.SSVC_LINE_TYPE_CD = C.SSVC_LINE_TYPE_CD AND B.SSVC_GROUP_CD = D.SLVL_CD AND B.SSVC_OBJ_CD = E.SLVL_CD ORDER BY B.SSVC_GROUP_CD ASC

SELECT DISTINCT B.SSVC_LINE_TYPE_CD , C.SSVC_LINE_TYPE_NM , B.SSVC_GROUP_CD , D.SLVL_NM AS SSVC_GROUP_NM , B.SSVC_OBJ_CD , E.SLVL_NM AS SSVC_OBJ_NM FROM MST.TB_USER_AUTH_TXN A ,MST.TB_LVL_BAS B ,MST.TB_SVC_LINE_TYPE_CD C ,MST.TB_LVL_CD D ,MST.TB_LVL_CD E WHERE 1=1 AND A.SUSER_ID = #{suserId, jdbcType=CHAR}
AND B.SSVC_LINE_TYPE_CD = #{tbLvlBasVo.ssvcLineTypeCd, jdbcType=CHAR}
AND B.SSVC_GROUP_CD = #{tbLvlBasVo.ssvcGroupCd, jdbcType=CHAR}
AND A.NLVL_BAS_SEQ = B.NLVL_BAS_SEQ AND B.SSVC_LINE_TYPE_CD = C.SSVC_LINE_TYPE_CD AND B.SSVC_GROUP_CD = D.SLVL_CD AND B.SSVC_OBJ_CD = E.SLVL_CD ORDER BY B.SSVC_OBJ_CD ASC
